import{_ as t,o as e,c as r,ag as i}from"./chunks/framework.f_9xDHrT.js";const u=JSON.parse('{"title":"开始使用","description":"按目标前往对应页面。","frontmatter":{"title":"开始使用","description":"按目标前往对应页面。"},"headers":[],"relativePath":"manual/start.md","filePath":"manual/start.md","lastUpdated":1778062636000}'),l={name:"manual/start.md"};function s(n,a,o,d,h,c){return e(),r("div",null,[...a[0]||(a[0]=[i('<h1 id="开始使用" tabindex="-1">开始使用 <a class="header-anchor" href="#开始使用" aria-label="Permalink to &quot;开始使用&quot;">​</a></h1><p>MissFisher 是一个简洁的钓鱼辅助插件，不适合纯萌新使用。</p><h2 id="能清单式全自动吗" tabindex="-1">能清单式全自动吗？ <a class="header-anchor" href="#能清单式全自动吗" aria-label="Permalink to &quot;能清单式全自动吗？&quot;">​</a></h2><p>不能，只在部分场景下可短期多轮次自动，通常只能在单轮次内自动。</p><p>你还必须自己准备背包空间、修装备和购买钓饵，自己在合适的窗口期或时机启动。</p><h2 id="能干什么" tabindex="-1">能干什么？ <a class="header-anchor" href="#能干什么" aria-label="Permalink to &quot;能干什么？&quot;">​</a></h2><h3 id="钓特定鱼类" tabindex="-1">钓特定鱼类 <a class="header-anchor" href="#钓特定鱼类" aria-label="Permalink to &quot;钓特定鱼类&quot;">​</a></h3><p>必须指定预设名，类脚本的有限自动钓鱼。</p><ul><li><strong><a href="./scenarios/fish">钓场之王、海钓中的普通海域稀有鱼、宠物、部分捕鱼人的特殊交付需求</a></strong><br> （不包括老主顾交易）</li></ul><h3 id="以模式按场景自动" tabindex="-1">以模式按场景自动 <a class="header-anchor" href="#以模式按场景自动" aria-label="Permalink to &quot;以模式按场景自动&quot;">​</a></h3><p>可自动调用预设，有额外的检测和辅助行为。</p><ul><li><p><strong><a href="./scenarios/ocean">出海垂钓</a>：</strong><br> 可以进行单轮全自动以完成渔分成就、收集蓝色稀有度鱼类、完成种类数量要求的奖励成就，也可使用耐力模式进行有限的多轮全自动。（不包含精确的图鉴收集）</p></li><li><p><strong><a href="./scenarios/cosmic">宇宙探索</a>：</strong><br> 可以随任务接取自动启动适合当前任务的预设（提供有可设置项），不包括自动刷任务/寻路到任务钓场。</p></li><li><p><strong><a href="./scenarios/diadem">云冠群岛</a>：</strong><br> 可以完成数个相关成就。（不包含精确的图鉴收集）</p></li></ul><h2 id="做不到的" tabindex="-1">做不到的 <a class="header-anchor" href="#做不到的" aria-label="Permalink to &quot;做不到的&quot;">​</a></h2><ul><li>不能高效练级</li><li>不能无脑帮你点亮图鉴</li><li>没有自动修理</li><li>没有自动精炼</li><li>没有自动精选</li><li>没有自动交易大地票据</li><li>没有自动购买钓饵</li><li>不能自动消除钓场警惕</li></ul><h2 id="相关插件依赖" tabindex="-1">相关插件依赖 <a class="header-anchor" href="#相关插件依赖" aria-label="Permalink to &quot;相关插件依赖&quot;">​</a></h2><p>MissFisher 依赖部分插件来提供额外功能。</p><p>可在主界面 - 标题栏的齿轮设置按钮打开设置页，找到插件依赖部分查看还未安装或启动的依赖插件。</p><table tabindex="0"><thead><tr><th style="text-align:center;">依赖的插件</th><th>MissFisher 用它来做什么</th></tr></thead><tbody><tr><td style="text-align:center;">Daily Routines</td><td>借用它的 Edge TTS 进行语音信息播报和提醒</td></tr><tr><td style="text-align:center;">vnavmesh</td><td>它可以提供地图内的自动寻路 / 导航</td></tr><tr><td style="text-align:center;">ICE</td><td>自动接取、刷取、提交宇宙探索任务</td></tr></tbody></table><h2 id="面向专业用户的内容" tabindex="-1">面向专业用户的内容 <a class="header-anchor" href="#面向专业用户的内容" aria-label="Permalink to &quot;面向专业用户的内容&quot;">​</a></h2><p>还在施工……</p>',20)])])}const b=t(l,[["render",s]]);export{u as __pageData,b as default};
